            let _ = writeln!(self.buf, "  nodesep=0.3; ranksep=0.3;");
            let _ = writeln!(self.buf,
                "  node [fontsize=8,fontname=\"Helvetica\",width=0.3,height=0.2,shape=record];");
            let _ = writeln!(self.buf,
