//! TEMPORARY dirty-room B byte gate — drives the clean RawRule seam and compares
//! to a live HS capture. Not a committed test; removed after the gate runs.

use tamarin_server::graph_clean::generate::{
    generate, EdgeStyle, EndRef, GraphNode, RawRule, SysEdge, System,
};
use tamarin_server::graph_clean::dot::to_dot;

fn drive(prems: &[&str], info: &str, concls: &[&str], fill: &str) -> String {
    let raw = RawRule::new(info, fill)
        .premises(prems.iter().map(|s| s.to_string()).collect())
        .conclusions(concls.iter().map(|s| s.to_string()).collect());
    let sys = System {
        nodes: vec![
            GraphNode::RawRule(raw),
            GraphNode::OpenTarget { node_var: "i".into(), premise_index: 0 },
        ],
        edges: vec![SysEdge::new(
            EndRef::Conclusion(0, 0),
            EndRef::Whole(1),
            EdgeStyle::Structural,
        )],
        legend_html: None,
        legend_edges: vec![],
    };
    to_dot(&generate(&sys))
}

#[test]
fn wide_probe_seam() {
    let out = drive(
        &["Fr( ~n.4 )", "In10( ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7 )"],
        "#vr.3 : Wide[Fired( ~n.4 )]",
        &[
            "Ack( ~n.4, <~n.7, ~n.7> )",
            "Big( ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7, ~n.7 )",
            "Out( ~n.4 )",
        ],
        "#d5d897",
    );
    let hs = std::fs::read_to_string(
        "/tmp/claude-1000/-home-kamilner-tamarin-rs/57f8e1bc-d495-4b36-93c0-033347d5034a/scratchpad/bgate/wide_hs.dot",
    )
    .unwrap();
    print!("{}", out);
    eprintln!("=== CLEAN SEAM OUTPUT ({} bytes) ===\n{}", out.len(), out);
    eprintln!("=== HS CAPTURE ({} bytes) ===\n{}", hs.len(), hs);
    if out == hs {
        eprintln!("RESULT: BYTE-IDENTICAL");
    } else {
        // find first divergence
        let ob = out.as_bytes();
        let hb = hs.as_bytes();
        let mut i = 0;
        while i < ob.len() && i < hb.len() && ob[i] == hb[i] {
            i += 1;
        }
        eprintln!("RESULT: DIVERGES at byte {}", i);
        let lo = i.saturating_sub(30);
        eprintln!("clean[..]: {:?}", &out[lo..(i + 40).min(out.len())]);
        eprintln!("hs   [..]: {:?}", &hs[lo..(i + 40).min(hs.len())]);
    }
    assert_eq!(out, hs, "wide probe seam byte mismatch");
}

