#[test]
fn wide_probe_ported() {
    // Confirm the CURRENT ported serializer (render_balanced) keeps the small
    // `Ack` cell on one line, matching HS — so the clean seam (which breaks it)
    // would REGRESS the route.
    use tamarin_server::handlers::dot::system_to_dot;
    use tamarin_theory::constraint::system::System as PSystem;
    use tamarin_theory::fact::{fresh_fact, out_fact, Fact, FactTag, Multiplicity};
    use tamarin_theory::rule::{
        ProtoRuleACInstInfo, ProtoRuleName, Rule, RuleAttributes, RuleInfo,
    };
    use tamarin_term::function_symbols::pair_sym;
    use tamarin_term::lterm::{LSort, LVar};
    use tamarin_term::term::{f_app_no_eq, Term};
    use tamarin_term::vterm::Lit;

    let n = Term::Lit(Lit::Var(LVar::new("n", LSort::Fresh, 4)));
    let x = Term::Lit(Lit::Var(LVar::new("n", LSort::Fresh, 7)));
    let x10 = || vec![x.clone(); 10];
    let pair = f_app_no_eq(pair_sym(), vec![x.clone(), x.clone()]);
    let info: RuleInfo<ProtoRuleACInstInfo, tamarin_theory::rule::IntrRuleACInfo> =
        RuleInfo::Proto(ProtoRuleACInstInfo {
            name: ProtoRuleName::Stand("Wide"),
            attributes: RuleAttributes::empty(),
            loop_breakers: Vec::new(),
        });
    let rule = Rule::new(
        info,
        vec![fresh_fact(n.clone()), Fact::new(FactTag::Proto(Multiplicity::Linear, "In10", 10), x10())],
        vec![
            Fact::new(FactTag::Proto(Multiplicity::Linear, "Ack", 2), vec![n.clone(), pair]),
            Fact::new(FactTag::Proto(Multiplicity::Linear, "Big", 10), x10()),
            out_fact(n.clone()),
        ],
        Vec::new(),
    );
    let mut sys = PSystem::empty();
    sys.add_node(LVar::new("i", LSort::Node, 0), rule);
    let dot = system_to_dot(&sys);
    // extract just the Ack cell text
    if let Some(p) = dot.find("Ack(") {
        let seg = &dot[p..(p + 60).min(dot.len())];
        eprintln!("PORTED Ack cell: {:?}", seg);
    }
    eprintln!("PORTED full record label:\n{}", dot);
}

